VALUES
  ('optician-moex-01909', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '何者最不可能是誘發三點九點角膜染色（3 and 9 o''clock corneal staining）之原因？', '["眨眼不足", "淚水不足", "鏡片下位", "鏡片較大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01910', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關有色裝飾性的隱形眼鏡之敘述，下列何者錯誤？', '["為增強效果，有廠商自行為彩色隱形眼鏡表面加添顏色，部分鏡片色素又太厚，有可能令鏡片透 氧度降低", "若色素塗在鏡片外層，可致鏡片不平滑，不但易造成眼睛受傷，還容易黏附細菌，增加配戴者受感 染風險", "如果自行網購有色裝飾性的隱形眼鏡，應選擇知名品牌，這樣鏡片的安全性及顏料素質才都有保障", "在眼科醫師或驗光師協助下，先評估是否適合戴隱形眼鏡，並選擇符合眼球弧度的鏡片，學習正 確護理鏡片程序，有助保護靈魂之窗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01911', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '當戴了軟式隱形眼鏡之後覺得刺痛感或灼熱感（stinging or burning），最常見的原因為何？', '["鐵屑跑入隱形眼鏡", "保養品或化妝品跑入隱形眼鏡", "隱形眼鏡太鬆", "浸泡隱形眼鏡溶液不正確使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01912', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡相關的瞼板腺功能障礙（contact-lens-associated  meibomian  gland  dysfunction, CL-MGD），下列敘述何者錯誤？', '["瞼板腺的分泌物變成渾濁的乳黃色", "伴有模糊視力", "淚液破裂時間減少", "可使用冰敷來緩解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01913', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列有關隱形眼鏡巨大乳突結膜炎（giant papillary conjunctivitis），下列何者錯誤？', '["因為大眾所使用的隱形眼鏡較多屬於頻繁更換性的隱形眼鏡，目前較少見到隱形眼鏡巨大乳突結 膜炎", "較軟材質的隱形眼鏡比較容易造成", "造成原因一般認為和免疫反應與機械性摩擦相關", "若是單純由機械性摩擦所造成，大多停戴隱形眼鏡兩周即可達到改善"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01914', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '配戴隱形眼鏡比較不會增加感染那種病菌的機會？', '["鐮刀菌角膜炎（fusarium keratitis）", "綠膿桿菌角膜炎 （pseudomonas keratitis）", "棘狀阿米巴角膜炎（acanthamoeba keratitis）", "皰疹性角膜炎（herpes keratitis）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01915', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '單焦球面軟式隱形眼鏡配戴者最近出現老花現象，想改配同步視覺隱形眼鏡（simultaneous vision design）。下列驗配注意事項及患者說明，何者錯誤？', '["在驗配時要注意瞳孔大小、鏡片中心定位，因為這些都可能影響視力品質", "由於折射率的關係，若要讓遠及近距離的影像對比度相同，則遠區域的瞳孔覆蓋範圍必須比近區 域大一倍", "由於清晰與失焦的影像同時存在會互相影響，因此清晰影像的對比度可能會降低", "由於不同距離的成像有些是清晰有些是失焦，影像品質可能無法像單焦隱形眼鏡那麼好"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01916', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '每種老花隱形眼鏡設計皆有它的優缺點與較適合配戴的患者，下列何種患者驗配軟式老花多焦點隱 形眼鏡（soft multifocal）的成功率較低？', '["偶爾需要使用電腦的中度遠視患者", "目前已配戴軟式單焦隱形眼鏡的中度近視患者", "正視眼（emmetropic）僅需老花矯正患者", "度數為-3.00DS/-0.75DC×180的患者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01917', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '利用部分單眼視覺（partial monovision）驗配老花隱形眼鏡，下列敘述何者錯誤？', '["適用小於1.5 D老花加入度（ADD）者", "可提供較單眼視覺（monovision）佳的立體視覺", "可能需要外加看近用眼鏡", "可提供較好的中距離視力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01918', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於配戴雙焦點隱形眼鏡，下列何者錯誤？', '["較不適用於角膜不規則的人", "適用於弱視的人", "相對於眼鏡來說，比較不適用於對視力品質要求高的人", "適用於對長時間閱讀需求比較少的人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
